export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(cellKey));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const entry = neighborCounts.get(key);
      if (entry) entry.count++;
      else neighborCounts.set(key, { cell: neighbor, count: 1 });
    }
  }

  const survives = (key: string, count: number): boolean =>
    liveSet.has(key) ? count === 2 || count === 3 : count === 3;

  return [...neighborCounts.entries()]
    .filter(([key, { count }]) => survives(key, count))
    .map(([, { cell }]) => cell);
}

