export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(cellKey));
  const candidates = liveCells.flatMap(neighborsOf);

  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const cell of candidates) {
    const key = cellKey(cell);
    const entry = counts.get(key) ?? { cell, count: 0 };
    entry.count++;
    counts.set(key, entry);
  }

  const survives = (key: string, count: number): boolean =>
    count === 3 || (count === 2 && liveSet.has(key));

  return [...counts.entries()]
    .filter(([key, { count }]) => survives(key, count))
    .map(([, { cell }]) => cell);
}
